 52→type FoodItemModalProps = {
 53→  item?: CartItem
 54→  cartItems: CartItem[]
 55→  onClose: () => void
 56→  onItemSave: (item: CartItem) => void
 57→  onItemRemove: (item: CartItem) => void
 58→}
 59→
 60→export const FoodItemModal = ({
 61→  item,
 62→  cartItems,
 63→  onClose,
 64→  onItemSave,
 65→  onItemRemove,
 66→}: FoodItemModalProps) => {
 67→  const [quantity, setQuantity] = useState(0)
 68→
 69→  const saveItem = useCallback(() => {
 70→    if (item) {
 71→      if (quantity === 0) {
 72→        onItemRemove(item)
 73→      } else {
 74→        onItemSave({ ...item, quantity })
 75→      }
 76→    }
 77→
 78→    onClose()
 79→  }, [quantity, onClose, onItemRemove, item, onItemSave])
 80→
 81→  useEffect(() => {
 82→    const cartItem = item && cartItems.find((c) => c.id === item.id)
 83→    setQuantity(cartItem?.quantity || 1)
 84→    return () => setQuantity(0)
 85→  }, [cartItems, item])
 86→
 87→  return (
 88→    <Modal isOpen={!!item} onClose={onClose}>
 89→      {item && (
 90→        <div>
 91→          <TopContainer>
 92→            <Heading>{item.name}</Heading>
 93→            <StyledBody>{item.description}</StyledBody>
 94→          </TopContainer>
 95→          <BottomContainer>
 96→            <ButtonsContainer>
 97→              <Button
 98→                aria-label="decrease quantity by one"
 99→                round
100→                clear
101→                icon="minus"
102→                onClick={() => setQuantity(quantity - 1)}
103→                disabled={quantity <= 1}
104→              />
105→              <Body type="span">{quantity}</Body>
106→              <Button
107→                aria-label="increase quantity by one"
108→                round
109→                clear
110→                icon="plus"
111→                onClick={() => setQuantity(quantity + 1)}
112→                disabled={quantity >= 10}
113→              />
114→            </ButtonsContainer>
115→            <StyledButton aria-label="confirm" onClick={saveItem}>
116→              add for {toCurrency(item.price * quantity)}
117→            </StyledButton>
118→          </BottomContainer>
119→        </div>
120→      )}
121→    </Modal>
122→  )
123→}
