import React from 'react'
import { Link } from 'react-router-dom'
import styled from 'styled-components'

const BreadcrumbContainer = styled.div(
  ({ theme: { color } }) => `
  margin-top: 2rem;
  margin-bottom: 2rem;
  a,
  p {
    color: ${color.secondaryText};
    text-transform: lowercase;
  }
`
)

const LinkText = styled.p`
  display: inline-block;
  text-decoration: underline;
`

const PlainText = styled.p`
  display: inline;
  font-weight: lighter;
`

const Separator = styled.span`
  margin: 0 0.5rem;
`

interface BreadcrumbProps {
  items: {
    label: string
    path?: string
  }[]
}

export const Breadcrumb = ({ items }: BreadcrumbProps) => {
  return (
    <BreadcrumbContainer>
      {items.map((item, index) => (
        <React.Fragment key={index}>
          {index > 0 && <Separator>/</Separator>}
          {item.path ? (
            <LinkText>
              <Link to={item.path}>{item.label}</Link>
            </LinkText>
          ) : (
            <PlainText>{item.label}</PlainText>
          )}
        </React.Fragment>
      ))}
    </BreadcrumbContainer>
  )
}

import { useMemo } from 'react'

import { ShoppingCartItem } from '../ShoppingCartItem/ShoppingCartItem'
import { CartItem } from '../../../app-state/cart'
import { Body } from '../../typography/Body'
import { toCurrency } from '../../../helpers'

import {
  OrderSummaryContainer,
  BottomContainer,
  CartItemsContainer,
  StyledHeading,
} from './OrderSummary.styles'

type OrderSummaryProps = {
  cartItems: CartItem[]
}

export const OrderSummary = ({ cartItems }: OrderSummaryProps) => {
  const totalPrice = useMemo(
    () => cartItems.map((item) => item.quantity * item.price).reduce((acc, next) => acc + next, 0),
    [cartItems]
  )
  return (
    <>
      <OrderSummaryContainer>
        <StyledHeading level={3} $withMargin>
          Your order
        </StyledHeading>
        <CartItemsContainer>
          {cartItems.length > 0 ? (
            cartItems.map((item) => <ShoppingCartItem key={item.id} item={item} />)
          ) : (
            <Body>Your cart is empty.</Body>
          )}
        </CartItemsContainer>
        <BottomContainer>
          <Body>Total</Body>
          <StyledHeading level={2}>{toCurrency(totalPrice)}</StyledHeading>
        </BottomContainer>
      </OrderSummaryContainer>
    </>
  )
}

